--
-- Table structure for table `machine_injector`
--

DROP TABLE IF EXISTS `machine_injector`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `machine_injector` (
  `id` int NOT NULL AUTO_INCREMENT,
  `machine_id` int NOT NULL,
  `title` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `name` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `serial_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `screw_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '螺杆类别',
  `screw_diameter` decimal(10,0) DEFAULT '0' COMMENT '螺杆直径',
  `screw_length` decimal(10,2) DEFAULT NULL COMMENT '螺杆长度',
  `screw_length_diameter_ratio` decimal(10,2) DEFAULT '0.00' COMMENT '螺杆长径比L/D',
  `screw_compression_ratio` decimal(10,2) DEFAULT '0.00' COMMENT '螺杆压缩比',
  `max_injection_volume` decimal(10,2) DEFAULT NULL COMMENT '最大注射容积',
  `max_injection_weight` decimal(10,2) DEFAULT '0.00' COMMENT '最大注射重量',
  `max_injection_stroke` decimal(10,2) DEFAULT '0.00' COMMENT '最大注射行程',
  `max_injection_pressure` decimal(10,0) DEFAULT '0' COMMENT '最大注射压力',
  `max_injection_velocity` decimal(10,0) DEFAULT '0' COMMENT '最大注射速度',
  `max_holding_pressure` decimal(10,0) DEFAULT '0' COMMENT '最大保压压力',
  `max_holding_velocity` decimal(10,0) DEFAULT '0' COMMENT '最大保压速度',
  `max_metering_pressure` decimal(10,0) DEFAULT NULL COMMENT '最大计量压力',
  `max_screw_rotation_speed` decimal(10,0) DEFAULT '0' COMMENT '最大螺杆转速',
  `max_metering_back_pressure` decimal(10,0) DEFAULT '0' COMMENT '最大计量背压',
  `max_decompression_pressure` decimal(10,0) DEFAULT NULL COMMENT '最大射退压力',
  `max_decompression_velocity` decimal(10,0) DEFAULT NULL COMMENT '最大射退速度',
  `plasticizing_capacity` decimal(10,0) DEFAULT '0' COMMENT '塑化能力',
  `nozzle_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `nozzle_protrusion` decimal(10,2) DEFAULT NULL COMMENT '螺杆伸出量',
  `nozzle_hole_diameter` decimal(10,2) DEFAULT '0.00' COMMENT '喷嘴孔直径',
  `nozzle_sphere_diameter` decimal(10,2) DEFAULT '0.00' COMMENT '喷嘴球径',
  `nozzle_force` decimal(10,0) DEFAULT NULL COMMENT '喷嘴接触力',
  `barrel_heating_sections` decimal(10,0) DEFAULT '0' COMMENT '料筒加热段数',
  `barrel_heating_power` decimal(10,2) DEFAULT '0.00' COMMENT '料筒加热功率',
  `max_set_injection_pressure` decimal(10,2) DEFAULT NULL COMMENT '最大可设定注射压力',
  `max_set_injection_velocity` decimal(10,2) DEFAULT NULL COMMENT '最大可设定注射速度',
  `max_set_holding_pressure` decimal(10,2) DEFAULT NULL COMMENT '最大可设定保压压力',
  `max_set_holding_velocity` decimal(10,2) DEFAULT NULL COMMENT '最大可设定保压速度',
  `max_set_metering_pressure` decimal(10,2) DEFAULT NULL COMMENT '最大可设定计量压力',
  `max_set_screw_rotation_speed` decimal(10,2) DEFAULT NULL COMMENT '最大可设定螺杆转速',
  `max_set_metering_back_pressure` decimal(10,2) DEFAULT NULL COMMENT '最大可设定计量背压',
  `max_set_decompression_pressure` decimal(10,2) DEFAULT NULL COMMENT '最大可设定射退压力',
  `max_set_decompression_velocity` decimal(10,2) DEFAULT NULL COMMENT '最大可设定射退速度',
  `max_injection_stage` int DEFAULT '6',
  `max_holding_stage` int DEFAULT '5',
  `max_metering_stage` int DEFAULT '4',
  `max_temperature_stage` int DEFAULT '10',
  `max_opening_and_clamping_stage` int DEFAULT NULL,
  `enhancement_ratio` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `cylinder_numer` int DEFAULT NULL COMMENT '油缸数',
  `cylinder_diameter` decimal(10,2) DEFAULT NULL COMMENT '油缸直径',
  `piston_rod_diameter` decimal(10,2) DEFAULT NULL COMMENT '活塞杆直径',
  `use_small_size` tinyint(1) DEFAULT NULL COMMENT '活塞杆位于注射侧',
  `cylinder_area` decimal(10,2) DEFAULT NULL,
  `intensification_ratio` decimal(10,2) DEFAULT NULL,
  `max_ejector_stage` int DEFAULT NULL,
  `max_ejector_forward_velocity` decimal(10,2) DEFAULT NULL,
  `max_ejector_backward_velocity` decimal(10,2) DEFAULT NULL,
  `max_mold_opening_velocity` decimal(10,2) DEFAULT NULL,
  `max_mold_clamping_velocity` decimal(10,2) DEFAULT NULL,
  `max_set_ejector_forward_velocity` decimal(10,2) DEFAULT NULL,
  `max_set_ejector_backward_velocity` decimal(10,2) DEFAULT NULL,
  `max_set_mold_opening_velocity` decimal(10,2) DEFAULT NULL,
  `max_set_mold_clamping_velocity` decimal(10,2) DEFAULT NULL,
  `max_injection_rate` decimal(10,2) DEFAULT NULL,
  `max_holding_rate` decimal(10,2) DEFAULT NULL,
  `max_screw_linear_velocity` decimal(10,2) DEFAULT NULL,
  `screw_area` decimal(10,2) DEFAULT NULL,
  `screw_circumference` decimal(10,2) DEFAULT NULL,
  `max_decompression_rate` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `machine_injector_machine_id_fk_mahine_id` (`machine_id`),
  CONSTRAINT `machine_injector_machine_id_fk_mahine_id` FOREIGN KEY (`machine_id`) REFERENCES `machine` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=421 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_bin;
/*!40101 SET character_set_client = @saved_cs_client */;

