DROP TABLE IF EXISTS `polymer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `polymer` (
  `id` int NOT NULL AUTO_INCREMENT,
  `company_id` int DEFAULT '-1',
  `series` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `trademark` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '牌号',
  `manufacturer` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '厂商',
  `abbreviation` varchar(200) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL COMMENT '材料名称缩写',
  `category` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '材料类别:结晶性,无定形',
  `data_source` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '数据源',
  `data_status` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `internal_id` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `level_code` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `vendor_code` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `max_melt_temperature` decimal(10,2) DEFAULT NULL COMMENT '最大成型温度(℃)',
  `min_melt_temperature` decimal(10,2) DEFAULT NULL COMMENT '最小成型温度(℃)',
  `recommend_melt_temperature` decimal(10,2) DEFAULT NULL COMMENT '推荐成型温度(℃)',
  `max_mold_temperature` decimal(10,2) DEFAULT NULL COMMENT '最大模具温度(℃)',
  `min_mold_temperature` decimal(10,2) DEFAULT NULL COMMENT '最小模具温度(℃)',
  `recommend_mold_temperature` decimal(10,2) DEFAULT NULL COMMENT '推荐模具温度(℃)',
  `max_shear_linear_speed` decimal(10,2) DEFAULT NULL COMMENT '最大剪切线速度（mm/s）',
  `min_shear_linear_speed` decimal(10,2) DEFAULT NULL COMMENT '最小剪切线速度（mm/s）',
  `recommend_shear_linear_speed` decimal(10,2) DEFAULT NULL COMMENT '推荐剪切线速度（mm/s）',
  `recommend_injection_rate` decimal(10,2) DEFAULT NULL COMMENT '推荐注射速率',
  `recommend_back_pressure` decimal(10,2) DEFAULT NULL COMMENT '推荐背压',
  `degradation_temperature` decimal(10,2) DEFAULT NULL COMMENT '塑料降解温度(℃)',
  `ejection_temperature` decimal(10,2) DEFAULT NULL COMMENT '顶出温度(℃)',
  `barrel_residence_time` decimal(10,2) DEFAULT NULL COMMENT '料筒滞留时间',
  `max_sheer_rate` decimal(10,2) DEFAULT NULL COMMENT '最大许可剪切速率(1/s)',
  `max_sheer_stress` decimal(10,2) DEFAULT NULL COMMENT '最大许可剪切应力(MPa)',
  `dry_temperature` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '干燥温度(℃)',
  `dry_time` varchar(64) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '干燥时间',
  `dry_method` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '干燥方式',
  `viscosity_model` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '粘度模型',
  `cross_WLF_n` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `cross_WLF_Tau` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'Pa',
  `cross_WLF_D1` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'Pa-s',
  `cross_WLF_D2` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'k',
  `cross_WLF_D3` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'k/Pa',
  `cross_WLF_A1` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `cross_WLF_A2` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT 'k',
  `c1` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '接合点损失法系数(Pa^(1-c2))',
  `c2` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '接合点损失法系数',
  `switch_temp` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '转换温度(℃)',
  `viscosity_index` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '粘度指数',
  `MFR_temp` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '温度（℃）',
  `MFR_load` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '载入（Kg）',
  `MFR_measure` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '测量的MFR（g/10min）',
  `melt_density` decimal(10,4) DEFAULT NULL COMMENT '熔体密度(g/ccm)',
  `solid_density` decimal(10,4) DEFAULT NULL COMMENT '固体密度(g/ccm)',
  `Tait_pvT_b5` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b6` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b1m` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b2m` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b3m` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b4m` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b1s` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b2s` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b3s` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b4s` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b7` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b8` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `Tait_pvT_b9` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `E1` decimal(10,2) DEFAULT NULL,
  `E2` decimal(10,2) DEFAULT NULL,
  `v12` decimal(10,2) DEFAULT NULL,
  `v23` decimal(10,2) DEFAULT NULL,
  `G12` decimal(10,2) DEFAULT NULL,
  `Alpha1` decimal(10,2) DEFAULT NULL,
  `Alpha2` decimal(10,2) DEFAULT NULL,
  `average_horizontal_shrinkage` decimal(10,2) DEFAULT NULL,
  `average_vertical_shrinkage` decimal(10,2) DEFAULT NULL,
  `min_horizontal_shrinkage` decimal(10,2) DEFAULT NULL,
  `max_horizontal_shrinkage` decimal(10,2) DEFAULT NULL,
  `min_vertical_shrinkage` decimal(10,2) DEFAULT NULL,
  `max_vertical_shrinkage` decimal(10,2) DEFAULT NULL,
  `filler` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '填充物或者材料添加剂',
  `filler_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '添加料类型',
  `filler_shape` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '添加料形状',
  `filler_percentage` decimal(10,2) DEFAULT NULL COMMENT '添加料含量（%）',
  `filler_density` decimal(10,4) DEFAULT NULL,
  `filler_specific_heat` decimal(10,2) DEFAULT NULL,
  `filler_specific_thermal_conductivity` decimal(10,2) DEFAULT NULL,
  `filler_E1` decimal(10,2) DEFAULT NULL,
  `filler_E2` decimal(10,2) DEFAULT NULL,
  `filler_v12` decimal(10,2) DEFAULT NULL,
  `filler_v23` decimal(10,2) DEFAULT NULL,
