  `filler_vertical_tensile_strength` decimal(10,2) DEFAULT NULL,
  `filler_aspect_ratio` decimal(10,2) DEFAULT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted` tinyint(1) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=11940 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_bin;
