--
-- Table structure for table `process_index`
--

DROP TABLE IF EXISTS `process_index`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `process_index` (
  `id` int NOT NULL AUTO_INCREMENT,
  `company_id` int DEFAULT NULL,
  `process_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `status` tinyint DEFAULT NULL,
  `mold_id` int DEFAULT NULL,
  `mold_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '产品编号',
  `cavity_num` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `runner_length` decimal(10,2) DEFAULT NULL COMMENT '流道长度',
  `runner_weight` decimal(10,2) DEFAULT NULL COMMENT '流道重量',
  `gate_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '浇口类型',
  `gate_num` int DEFAULT NULL COMMENT '浇口个数',
  `gate_shape` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '浇口形状',
  `gate_area` decimal(10,2) DEFAULT NULL COMMENT '浇口横截面积',
  `gate_radius` decimal(10,2) DEFAULT NULL COMMENT '浇口半径(圆)',
  `gate_length` decimal(10,2) DEFAULT NULL COMMENT '浇口长(矩形)',
  `gate_width` decimal(10,2) DEFAULT NULL COMMENT '浇口宽(矩形)',
  `inject_part` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT '‘0’',
  `product_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '模具温度',
  `product_category` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `product_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '产品类型',
  `product_name` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '产品名称',
  `product_total_weight` decimal(10,2) DEFAULT NULL COMMENT '产品重量',
  `product_ave_thickness` decimal(10,2) DEFAULT NULL COMMENT '平均厚度',
  `product_max_thickness` decimal(10,2) DEFAULT NULL COMMENT '最大厚度',
  `product_max_length` decimal(10,2) DEFAULT NULL COMMENT '最大长度',
  `machine_id` int DEFAULT NULL,
  `machine_data_source` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `machine_trademark` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `machine_serial_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `pressure_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 'Mpa' COMMENT '压力单位',
  `velocity_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 'mm/s' COMMENT '速度单位',
  `temperature_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT '℃' COMMENT '温度单位',
  `time_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 's' COMMENT '时间单位',
  `position_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 'mm' COMMENT '长度单位',
  `clamping_force_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 'Ton' COMMENT '锁模力单位',
  `screw_rotation_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT 'rpm',
  `power_unit` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `polymer_id` int DEFAULT NULL,
  `polymer_abbreviation` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `polymer_trademark` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `injection_stage` int DEFAULT NULL,
  `holding_stage` int DEFAULT NULL,
  `VP_switch_mode` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `metering_stage` int DEFAULT NULL,
  `decompressure_mode_before_metering` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `decompressure_mode_after_metering` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `barrel_temperature_stage` int DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted` tinyint(1) DEFAULT '0',
  `data_sources` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `mold_trials_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `subrule_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `process_index_fk_company_id` (`company_id`),
  CONSTRAINT `process_index_fk_company_id` FOREIGN KEY (`company_id`) REFERENCES `company` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2170 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_bin;
/*!40101 SET character_set_client = @saved_cs_client */;

