DROP TABLE IF EXISTS `rule_keyword`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_keyword` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '变量名',
  `level` int DEFAULT NULL COMMENT '模糊级别',
  `all_range_min` int DEFAULT NULL COMMENT '参数取值范围最小值',
  `all_range_max` int DEFAULT NULL COMMENT '参数取值范围最大值',
  `action_range_min` int DEFAULT NULL COMMENT '参数调整区间最小值',
  `action_range_max` int DEFAULT NULL COMMENT '参数调整区间最大值',
  `action_max_val` int DEFAULT NULL COMMENT '参数单次最大调整量',
  `keyword_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '类型',
  `comment` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT '注释',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted` tinyint DEFAULT NULL,
  `subrule_no` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `product_small_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `polymer_abbreviation` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `rule_type` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL,
  `show_on_page` tinyint(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id_UNIQUE` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2352 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_bin COMMENT='规则管理';
